import styled, { css } from 'styled-components'

import { breakpoints } from '../../styles/breakpoints'
import { Body } from '../typography'

export type CategoryProps = {
  id?: string
  title: string
  photoUrl: string
  round?: boolean
}

const Container = styled.figure<{ $round: boolean }>(
  ({ $round, theme: { color, borderRadius } }) => css`
    display: flex;
    cursor: pointer;
    position: relative;
    flex-direction: ${$round ? 'column' : 'row'};
    align-items: ${$round ? 'center' : 'start'};
    border-radius: ${borderRadius.s};
    background: ${$round ? color.cardBackground : 'transparent'};
    height: 100%;
    width: 100%;
    min-width: 50px;
    max-width: ${$round ? '200px' : 'auto'};
    max-height: ${$round ? '200px' : '309px'};
    margin: 0;
    padding: ${$round ? '1.5rem 2rem' : '0'};

    &:hover {
      opacity: 0.9;
    }

    @media ${breakpoints.M} {
      padding: ${$round ? '1.5rem 0' : '0'};
    }
  `
)

const Image = styled.img(
  ({ theme: { borderRadius } }) => css`
    object-fit: cover;
    width: auto;
    border-radius: ${borderRadius.s};
    width: 100%;
    height: 100%;
    min-width: 50px;
    min-height: 50px;
    max-height: 300px;
  `
)

const RoundImage = styled(Image)(
  ({ theme: { borderRadius } }) => css`
    border-radius: ${borderRadius.round};
    width: 4.5rem;
    height: 4.5rem;
    min-width: 4.5rem;
    min-height: 4.5rem;
    max-height: 200px;
    @media ${breakpoints.M} {
      width: 6.5rem;
      height: 6.5rem;
      min-width: 6.5rem;
      min-height: 6.5rem;
    }
  `
)

const FloatingTitle = styled.figcaption(
  ({ theme: { color, borderRadius } }) => css`
    position: absolute;
    top: 1.5rem;
    left: 1.5rem;
    border-radius: ${borderRadius.s};
    background: #202020;
    padding: 8px 16px;
    text-shadow: 2px 1px 2px rgba(0, 0, 0, 0.5);
    span {
      color: ${color.white};
    }
  `
)

const Title = styled.figcaption`
  padding-top: 1rem;
`

const Rounded = ({ title, photoUrl: url }: CategoryProps) => (
  <>
    <RoundImage src={url} alt="restaurant category" />
    <Title>
      <Body type="span">{title}</Body>
    </Title>
  </>
)

const Squared = ({ title, photoUrl: url }: CategoryProps) => (
  <>
    <Image src={url} alt="restaurant category" />
    <FloatingTitle>
      <Body type="span" fontWeight="medium">
        {title}
      </Body>
    </FloatingTitle>
  </>
)

export const Category = ({ photoUrl, title, round = false }: CategoryProps) => {
  return (
    <Container $round={round} data-testid={title}>
      {round ? (
        <Rounded photoUrl={photoUrl} title={title} />
      ) : (
        <Squared photoUrl={photoUrl} title={title} />
      )}
    </Container>
  )
}

import styled from 'styled-components'
import { useNavigate } from 'react-router-dom'
import Carousel, { type ArrowProps, type CarouselProps } from 'react-multi-carousel'

import { useFetchRestaurants } from '../../../../api/hooks'
import { IconButton } from '../../../../components/IconButton'
import { PageSection } from '../../../../components/PageSection'
import { RestaurantCard, RestaurantCardSkeleton } from '../../../../components/RestaurantCard'
import { Restaurant } from '../../../../types'
import { isMobile } from '../../../../helpers'

const PreviousButton = styled(IconButton)`
  position: absolute;
  left: 0;
`

const NextButton = styled(IconButton)`
  position: absolute;
  right: 0;
`

type RestaurantsSectionProps = {
  title: string
}

const CustomArrow = (props: Partial<CarouselProps & ArrowProps> & { isNext?: boolean }) => {
  // filter out unnecessary props coming from react-multi-carousel
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  const { carouselState, rtl, isNext, ...rest } = props
  return isNext ? (
    <NextButton name="arrow-right" {...rest} />
  ) : (
    <PreviousButton name="arrow-left" {...rest} />
  )
}

export const RestaurantsSection = ({ title }: RestaurantsSectionProps) => {
  const navigate = useNavigate()

  const { restaurants, status } = useFetchRestaurants()

  const isOnMobile = isMobile()
  return (
    <PageSection title={title}>
      <Carousel
        draggable={isOnMobile}
        partialVisible={isOnMobile}
        customLeftArrow={<CustomArrow />}
        customRightArrow={<CustomArrow isNext />}
        responsive={{
          desktop: {
            breakpoint: { max: 5000, min: 1024 },
            items: 3,
            slidesToSlide: 3,
          },
          tablet: {
            breakpoint: { max: 1024, min: 464 },
            items: 2,
            paritialVisibilityGutter: 50,
          },
          mobile: {
            breakpoint: { max: 464, min: 0 },
            items: 1,
            paritialVisibilityGutter: 30,
          },
        }}
        containerClass="carousel-container"
        removeArrowOnDeviceType={['tablet', 'mobile']}
        itemClass="carousel-item"
      >
        {status === 'loading'
          ? Array.from({ length: 3 }).map((_, index) => <RestaurantCardSkeleton key={index} />)
          : restaurants.map((restaurant: Restaurant, index: number) => (
              <RestaurantCard
                key={restaurant.name + index}
                {...restaurant}
                onClick={() => navigate(`/restaurants/${restaurant.id}`)}
              />
            ))}
      </Carousel>
    </PageSection>
  )
}

import * as React from 'react'
import styled from 'styled-components'

import { Header, HeaderComponent } from '../components/Header/Header'
import { Footer } from '../components/Footer/Footer'

const Container = styled.div`
  min-height: calc(100vh - 200px);
`

type PageTemplateProperties = {
  type?: 'default' | 'sticky-header' | 'basic'
}

export const PageTemplate: React.FC<React.PropsWithChildren<PageTemplateProperties>> = ({
  type = 'default',
  children,
}) => {
  switch (type) {
    case 'sticky-header': {
      return (
        <>
          <Header sticky />
          <Container>{children}</Container>
          <Footer />
        </>
      )
    }
    case 'basic': {
      return (
        <>
          <HeaderComponent logoOnly />
          <Container>{children}</Container>
        </>
      )
    }
  }

  return (
    <>
      <Header />
      <Container>{children}</Container>
      <Footer />
    </>
  )
}

