  1→import { useState, ChangeEvent } from 'react'
  2→import { useNavigate } from 'react-router-dom'
  3→
  4→import { saveOrderAction } from '../../../../app-state/order'
  5→import { useAppDispatch, useAppSelector } from '../../../../app-state'
  6→import { clearCartAction, selectCartItems } from '../../../../app-state/cart'
  7→import { Button } from '../../../../components/Button'
  8→import { Input } from '../../../../components/forms/Input'
  9→import { type DeliveryDetailsFormData } from './validation'
 10→
 11→type DeliveryDetailsProps = {
 12→  formData: DeliveryDetailsFormData
 13→  setFormData: (data: Partial<DeliveryDetailsFormData>) => void
 14→  onPrevious: () => void
 15→}
 16→
 17→type FormErrors = {
 18→  [K in keyof DeliveryDetailsFormData]?: string
 19→}
 20→
 21→const deliveryFields: (keyof DeliveryDetailsFormData)[] = ['address', 'city', 'postcode']
 22→
 23→export const DeliveryDetails = ({ formData, setFormData, onPrevious }: DeliveryDetailsProps) => {
 24→  const navigate = useNavigate()
 25→  const dispatch = useAppDispatch()
 26→  const cartItems = useAppSelector(selectCartItems)
 27→  const [errors, setErrors] = useState<FormErrors>({})
 28→  const [form, setForm] = useState<DeliveryDetailsFormData>(formData)
 29→  const [isSubmitted, setIsSubmitted] = useState(false)
 30→
 31→  const validateField = (
 32→    name: keyof DeliveryDetailsFormData,
 33→    value: string
 34→  ): string | undefined => {
 35→    if (!value) return 'Required'
 36→
 37→    switch (name) {
 38→      case 'address': {
 39→        return value.length < 5 ? 'Please enter a valid address' : undefined
 40→      }
 41→      case 'city': {
 42→        return value.length < 2 ? 'Please enter a valid city' : undefined
 43→      }
 44→      case 'postcode': {
 45→        return /^[0-9]{4}[A-Z]{2}$/.test(value)
 46→          ? undefined
 47→          : 'Please enter a valid postcode (e.g., 1234AB)'
 48→      }
 49→      default: {
 50→        return undefined
 51→      }
 52→    }
 53→  }
 54→
 55→  const handleChange = (e: ChangeEvent<HTMLInputElement>) => {
 56→    const { name, value } = e.target
 57→    setForm((prev) => ({ ...prev, [name]: value }))
 58→
 59→    if (isSubmitted) {
 60→      const error = validateField(name as keyof DeliveryDetailsFormData, value)
 61→      setErrors((prev) => ({
 62→        ...prev,
 63→        [name]: error,
 64→      }))
 65→    }
 66→  }
 67→
 68→  const handleComplete = () => {
 69→    setIsSubmitted(true)
 70→
 71→    // Validate only delivery fields
 72→    const newErrors: FormErrors = {}
 73→    let hasErrors = false
 74→
 75→    for (const field of deliveryFields) {
 76→      const error = validateField(field, form[field])
 77→      if (error) {
 78→        newErrors[field] = error
 79→        hasErrors = true
 80→      }
 81→    }
 82→
 83→    setErrors(newErrors)
 84→
 85→    if (!hasErrors) {
 86→      setFormData(form)
 87→      dispatch(saveOrderAction(cartItems))
 88→      dispatch(clearCartAction())
 89→      navigate('/success')
 90→    }
 91→  }
 92→
 93→  return (
 94→    <div className="form">
 95→      <Input
 96→        label="Streetname and housenumber"
 97→        placeholder="Some street, 13"
 98→        name="address"
 99→        value={form.address}
100→        onChange={handleChange}
101→        error={isSubmitted ? errors.address : undefined}
102→      />
103→      <Input
104→        label="Postcode"
105→        placeholder="AAAAXX"
106→        name="postcode"
107→        value={form.postcode}
108→        onChange={handleChange}
109→        error={isSubmitted ? errors.postcode : undefined}
110→      />
111→      <Input
112→        label="City"
113→        placeholder="Amsterdam"
114→        name="city"
115→        value={form.city}
116→        onChange={handleChange}
117→        error={isSubmitted ? errors.city : undefined}
118→      />
119→      <div
120→        style={{
121→          display: 'flex',
122→          justifyContent: 'space-between',
123→        }}
124→      >
125→        <Button clear onClick={onPrevious}>
126→          Previous
127→        </Button>
128→        <Button onClick={handleComplete}>Complete order</Button>
129→      </div>
130→    </div>
131→  )
132→}
